	api := &API{
		now: func() time.Time { return time.Now() },
	}

	now := time.Now()
	req := SilenceBulkRequest{
		Silences: []Silence{
			{
				Matchers: []SilenceMatcher{
					{Name: "job", Value: "prometheus", Regex: false},
				},
				StartsAt:  now,
				EndsAt:    now.Add(1 * time.Hour),
				Comment:   "Valid silence",
				CreatedBy: "user1",
			},
			{
				Matchers: []SilenceMatcher{
					{Name: "alertname", Value: "TestAlert", Regex: false},
				},
				StartsAt:  now.Add(2 * time.Hour),
				EndsAt:    now, // Invalid: EndsAt before StartsAt
				Comment:   "Invalid silence",
				CreatedBy: "user2",
			},
		},
	}

	reqBody, err := json.Marshal(req)
	require.NoError(t, err)

	httpReq := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewBuffer(reqBody))
	result := api.postSilencesBulk(httpReq)

	// Should fail with index 1 error
	require.NotNil(t, result.err)
	require.Contains(t, result.err.Error(), "index 1")
	// Result should be error, not partial success
	require.Nil(t, result.data.(*SilenceBulkResponse)) || require.Empty(t, result.data.(*SilenceBulkResponse).SilenceIDs)
}

